import React, { useEffect, useState } from 'react';
import { supabase } from '../supabaseClient';
import { motion } from 'framer-motion';

const WordCloud = () => {
  const [keywords, setKeywords] = useState([]);

  useEffect(() => {
    fetchKeywords();
  }, []);

  const fetchKeywords = async () => {
    const { data: proposals } = await supabase
      .from('proposals')
      .select('content')
      .limit(50);

    if (proposals) {
      const allText = proposals.map(p => p.content).join(' ');
      const words = allText.toLowerCase().split(/\s+/);
      const stopWords = ['le', 'la', 'les', 'de', 'des', 'et', 'ou', 'pour', 'dans', 'avec', 'sans', 'sur', 'par', 'un', 'une', 'est', 'sont', 'être', 'avoir', 'faire', 'ce', 'cette', 'ces', 'ses', 'lui', 'elle', 'nous', 'vous', 'ils', 'elles'];
      
      const frequency = {};
      words.forEach(word => {
        if (word.length > 3 && !stopWords.includes(word)) {
          frequency[word] = (frequency[word] || 0) + 1;
        }
      });

      const sorted = Object.entries(frequency)
        .sort((a, b) => b[1] - a[1])
        .slice(0, 30)
        .map(([word, count]) => ({
          word,
          count,
          size: 16 + Math.min(count * 2, 48)
        }));

      setKeywords(sorted);
    }
  };

  return (
    <div className="word-cloud">
      <h3>Nuage de mots-clés</h3>
      <p>Analyse sémantique des contributions citoyennes</p>
      <div className="cloud-container">
        {keywords.map((kw, idx) => (
          <motion.span
            key={idx}
            className="cloud-word"
            style={{ fontSize: kw.size }}
            whileHover={{ scale: 1.1 }}
            initial={{ opacity: 0, scale: 0.5 }}
            animate={{ opacity: 1, scale: 1 }}
            transition={{ delay: idx * 0.02 }}
          >
            {kw.word}
          </motion.span>
        ))}
      </div>
    </div>
  );
};

export default WordCloud;
